import sqlite3
import hashlib
import os


def get_db_connection(db_path="legacy_app.db"):
    """Get a connection to the legacy database."""
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    return conn


def hash_password(password, salt=None):
    """Hash a password with a salt for secure storage."""
    if salt is None:
        salt = os.urandom(32)
    pwd_hash = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, 100000)
    return salt, pwd_hash


def init_users_table(db_path="legacy_app.db"):
    """Initialize the users table if it doesn't exist (legacy schema support)."""
    conn = get_db_connection(db_path)
    cursor = conn.cursor()
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT UNIQUE NOT NULL,
            password_hash BLOB NOT NULL,
            salt BLOB NOT NULL,
            is_active INTEGER DEFAULT 1,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            last_login TIMESTAMP
        )
    """)
    conn.commit()
    conn.close()


def register_user(username, password, db_path="legacy_app.db"):
    """Register a new user in the legacy database."""
    if not username or not password:
        return False, "Username and password are required."

    if len(password) < 8:
        return False, "Password must be at least 8 characters long."

    salt, pwd_hash = hash_password(password)
    conn = get_db_connection(db_path)
    cursor = conn.cursor()
    try:
        cursor.execute(
            "INSERT INTO users (username, password_hash, salt) VALUES (?, ?, ?)",
            (username, pwd_hash, salt)
        )
        conn.commit()
        return True, "User registered successfully."
    except sqlite3.IntegrityError:
        return False, "Username already exists."
    finally:
        conn.close()


